import { derived, writable } from 'svelte/store';
import { gameStore } from './gameStore';

export const gamePaused = writable(true);

export const gameWon = derived(
	gameStore,
	$gameStore => $gameStore.won,
	false,
);

export const exploreMode = derived(
	gameStore,
	$gameStore => $gameStore.exploring,
	false,
);

export const exploreFailed = derived(
	gameStore,
	$gameStore => $gameStore.exploreFailed,
	false,
);

export const currentHint = derived(
	gameStore,
	$gameStore => $gameStore.currentHint,
	null,
);
